  const re = /--([\w-]+)\s*:\s*([^;}\n]+)/g
  let m: RegExpExecArray | null
  while ((m = re.exec(css)) !== null) {
    result[`--${m[1].trim()}`] = m[2].trim()
  }
  return result
}

